# --- CoAP Constants ---
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes (class.detail encoded as single byte)
RESP_CREATED = 65       # 2.01
RESP_CONTENT = 69       # 2.05
RESP_CHANGED = 68       # 2.04
RESP_BAD_REQUEST = 128  # 4.00
RESP_UNAUTHORIZED = 129 # 4.01
RESP_NOT_FOUND = 132    # 4.04
RESP_METHOD_NOT_ALLOWED = 133  # 4.05
RESP_INTERNAL_ERROR = 160      # 5.00

# CoAP Option Numbers
OPT_URI_PATH = 11
OPT_CONTENT_FORMAT = 12
OPT_URI_QUERY = 15

# Content Formats
CONTENT_TEXT_PLAIN = 0
CONTENT_JSON = 50


# --- Security: Pre-Shared Key Token Verification ---
# In production, store this securely (e.g., hardware secure element)
# All clients in the mesh must share this key
_PSK = b'iot-mesh-secret-key-change-me-2024'
_TOKEN_VALIDITY_WINDOW = 300  # seconds


def _hmac_sha256(key, message):
    """Minimal HMAC-SHA256 for token verification on constrained devices."""
    block_size = 64
    if len(key) > block_size:
        key = hashlib.sha256(key).digest()
    key = key + b'\x00' * (block_size - len(key))

    o_key_pad = bytes([k ^ 0x5C for k in key])
    i_key_pad = bytes([k ^ 0x36 for k in key])

    inner = hashlib.sha256(i_key_pad + message).digest()
    return hashlib.sha256(o_key_pad + inner).digest()


def generate_auth_token(timestamp=None):
    """Generate a time-based authentication token for CoAP requests.
    Clients must include this as a URI-Query option: auth=<hex_token>
    """
    if timestamp is None:
        timestamp = int(time.time())
    # Quantize to validity window
    window = timestamp // _TOKEN_VALIDITY_WINDOW
    msg = struct.pack('>I', window)
    mac = _hmac_sha256(_PSK, msg)
    return mac[:8].hex()


def _verify_auth_token(token_hex):
    """Verify an authentication token against current and previous time windows."""
    if not token_hex or len(token_hex) != 16:
        return False
    try:
        token_bytes = bytes.fromhex(token_hex)
    except (ValueError, TypeError):
        return False

    now = int(time.time())
    # Check current window and previous window (clock skew tolerance)
    for offset in (0, -1, 1):
        window = (now // _TOKEN_VALIDITY_WINDOW) + offset
        msg = struct.pack('>I', window)
        expected = _hmac_sha256(_PSK, msg)[:8]
        if token_bytes == expected:
            return True
    return False


# --- Rate Limiting (per-IP, simple sliding window) ---
class RateLimiter:
    """Simple rate limiter to prevent DoS on constrained devices."""

    def __init__(self, max_requests=10, window_seconds=60, max_tracked=20):
        self._max_requests = max_requests
        self._window = window_seconds
        self._max_tracked = max_tracked
        self._clients = {}  # ip -> [timestamps]

    def is_allowed(self, client_ip):
        now = int(time.time())
        # Cleanup old entries if too many tracked
        if len(self._clients) > self._max_tracked:
            self._cleanup(now)

        if client_ip not in self._clients:
            self._clients[client_ip] = []

        # Remove expired timestamps
        cutoff = now - self._window
        self._clients[client_ip] = [
            t for t in self._clients[client_ip] if t > cutoff
        ]

        if len(self._clients[client_ip]) >= self._max_requests:
            return False

        self._clients[client_ip].append(now)
        return True

    def _cleanup(self, now):
        cutoff = now - self._window
        expired = [
            ip for ip, times in self._clients.items()
            if not times or max(times) < cutoff
        ]
        for ip in expired:
            del self._clients[ip]


# --- CoAP Message Parser/Builder ---
class CoapMessage:
    """Minimal CoAP message representation."""

    __slots__ = ('version', 'msg_type', 'token_length', 'code',
                 'message_id', 'token', 'options', 'payload')

    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = ACK
        self.token_length = 0
        self.code = EMPTY
        self.message_id = 0
        self.token = b''
        self.options = []  # list of (number, value)
        self.payload = b''

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage. Returns None on invalid data."""
        if not data or len(data) < 4:
            return None

        msg = CoapMessage()
        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.msg_type = (first_byte >> 4) & 0x03
        msg.token_length = first_byte & 0x0F

        if msg.version != COAP_VERSION:
            return None
        if msg.token_length > 8:
            return None

        msg.code = data[1]
        msg.message_id = (data[2] << 8) | data[3]

        offset = 4
        if msg.token_length > 0:
            if offset + msg.token_length > len(data):
                return None
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length

        # Parse options
        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                # Payload marker
                offset += 1
                msg.payload = data[offset:]
                break

            delta = (data[offset] >> 4) & 0x0F
            length = data[offset] & 0x0F
            offset += 1

            if delta == 13:
                if offset >= len(data):
                    return None
                delta = data[offset] + 13
                offset += 1
            elif delta == 14:
                if offset + 1 >= len(data):
                    return None
                delta = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2
            elif delta == 15:
                return None  # Reserved

            if length == 13:
                if offset >= len(data):
                    return None
                length = data[offset] + 13
                offset += 1
            elif length == 14:
                if offset + 1 >= len(data):
                    return None
                length = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2
            elif length == 15:
                return None  # Reserved

            option_number = prev_option_number + delta
            if offset + length > len(data):
                return None
            option_value = data[offset:offset + length]
            offset += length

            msg.options.append((option_number, option_value))
            prev_option_number = option_number

        return msg

    def to_bytes(self):
        """Serialize this CoapMessage to bytes."""
        first_byte = ((self.version & 0x03) << 6) | \
                     ((self.msg_type & 0x03) << 4) | \
                     (len(self.token) & 0x0F)

        buf = bytearray()
        buf.append(first_byte)
        buf.append(self.code & 0xFF)
        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        if self.token:
            buf.extend(self.token)

        # Encode options (must be sorted by option number)
        sorted_options = sorted(self.options, key=lambda x: x[0])
        prev_number = 0
        for opt_num, opt_val in sorted_options:
            delta = opt_num - prev_number
            length = len(opt_val)

            # Encode delta
            if delta < 13:
                d = delta
                d_ext = b''
            elif delta < 269:
                d = 13
                d_ext = bytes([delta - 13])
            else:
                d = 14
                d_ext = struct.pack('>H', delta - 269)

            # Encode length
            if length < 13:
                l = length
                l_ext = b''
            elif length < 269:
                l = 13
                l_ext = bytes([length - 13])
            else:
                l = 14
                l_ext = struct.pack('>H', length - 269)

            buf.append((d << 4) | l)
            buf.extend(d_ext)
            buf.extend(l_ext)
            if opt_val:
                buf.extend(opt_val)

            prev_number = opt_num

        if self.payload:
            buf.append(0xFF)
            buf.extend(self.payload)

        return bytes(buf)

    def get_uri_path(self):
        """Extract URI path from options."""
        parts = []
        for opt_num, opt_val in self.options:
            if opt_num == OPT_URI_PATH:
                try:
                    parts.append(opt_val.decode('utf-8'))
                except (UnicodeDecodeError, AttributeError):
                    parts.append(str(opt_val))
        return '/' + '/'.join(parts) if parts else '/'

    def get_uri_queries(self):
        """Extract URI query parameters as dict."""
        queries = {}
        for opt_num, opt_val in self.options:
            if opt_num == OPT_URI_QUERY:
                try:
                    q = opt_val.decode('utf-8')
                    if '=' in q:
                        k, v = q.split('=', 1)
                        queries[k] = v
                    else:
                        queries[q] = ''
                except (UnicodeDecodeError, AttributeError):
                    pass
        return queries

    def get_method(self):
        """Return the method code (GET=1, POST=2, PUT=3, DELETE=4)."""
        return self.code


